import { useEffect } from "react";

type Tone = "good" | "warning" | "danger" | "neutral";

const NUMBER_PATTERN = /-?\d[\d,]*(\.\d+)?/;

const TONE_STYLES: Record<Tone, { card: string; badge: string; dot: string }> = {
  good: {
    card: "linear-gradient(135deg, #10b981 0%, #047857 100%)",
    badge: "border-emerald-200 bg-emerald-50 text-emerald-700 dark:border-emerald-800 dark:bg-emerald-950/40 dark:text-emerald-300",
    dot: "bg-emerald-500",
  },
  warning: {
    card: "linear-gradient(135deg, #f59e0b 0%, #b45309 100%)",
    badge: "border-amber-200 bg-amber-50 text-amber-700 dark:border-amber-800 dark:bg-amber-950/40 dark:text-amber-300",
    dot: "bg-amber-500",
  },
  danger: {
    card: "linear-gradient(135deg, #ef4444 0%, #b91c1c 100%)",
    badge: "border-red-200 bg-red-50 text-red-700 dark:border-red-800 dark:bg-red-950/40 dark:text-red-300",
    dot: "bg-red-500",
  },
  neutral: {
    card: "linear-gradient(135deg, #4f46e5 0%, #1d4ed8 100%)",
    badge: "border-indigo-200 bg-indigo-50 text-indigo-700 dark:border-indigo-800 dark:bg-indigo-950/40 dark:text-indigo-300",
    dot: "bg-indigo-500",
  },
};

function parseNumber(text: string) {
  const match = text.replace(/,/g, "").match(NUMBER_PATTERN);
  return match ? Number(match[0]) : null;
}

function getContext() {
  const path = window.location.pathname.toLowerCase();
  const title = document.querySelector("h1")?.textContent?.toLowerCase() || "";
  return `${path} ${title}`;
}

function interpretResult(value: number, resultText: string) {
  const context = getContext();

  if (context.includes("bmi") || context.includes("body mass index")) {
    if (value < 18.5) return { tone: "warning" as const, label: "Underweight - Review Healthy Range" };
    if (value < 25) return { tone: "good" as const, label: "Normal Weight" };
    if (value < 30) return { tone: "warning" as const, label: "Overweight - Monitor Range" };
    return { tone: "danger" as const, label: "High BMI - Consider Guidance" };
  }

  if (context.includes("debt-to-income") || context.includes("dti") || context.includes("debt ratio")) {
    if (value < 36) return { tone: "good" as const, label: "Healthy Debt Ratio" };
    if (value <= 43) return { tone: "warning" as const, label: "Borderline - Watch Debt Load" };
    return { tone: "danger" as const, label: "High - Consider Reducing" };
  }

  if (context.includes("roi") || context.includes("return") || context.includes("profit") || resultText.includes("%")) {
    if (value > 0) return { tone: "good" as const, label: "Positive Result" };
    if (value === 0) return { tone: "warning" as const, label: "Break Even" };
    return { tone: "danger" as const, label: "Negative Result" };
  }

  if (context.includes("budget") || context.includes("cash flow") || context.includes("remaining income")) {
    if (value > 0) return { tone: "good" as const, label: "On Track" };
    if (value === 0) return { tone: "warning" as const, label: "Tight Budget" };
    return { tone: "danger" as const, label: "Over Budget" };
  }

  if (context.includes("loan") || context.includes("mortgage") || context.includes("payment")) {
    return { tone: "neutral" as const, label: "Payment Estimate Ready" };
  }

  if (value > 0) return { tone: "good" as const, label: "Good - Result Ready" };
  if (value < 0) return { tone: "danger" as const, label: "Needs Attention" };
  return { tone: "neutral" as const, label: "Result Ready" };
}

function findResultElements() {
  const marked = Array.from(document.querySelectorAll<HTMLElement>('[data-testid^="result-"]'));
  const visual = Array.from(document.querySelectorAll<HTMLElement>(".bg-gradient-to-br p")).filter((element) => {
    const className = typeof element.className === "string" ? element.className : "";
    return className.includes("font-black") || className.includes("font-extrabold");
  });

  return [...new Set([...marked, ...visual])];
}

function ensureBadge(resultElement: HTMLElement) {
  const text = resultElement.textContent?.trim() || "";
  const value = parseNumber(text);
  if (value === null || !Number.isFinite(value)) return;

  const interpretation = interpretResult(value, text.toLowerCase());
  const styles = TONE_STYLES[interpretation.tone];
  const card = resultElement.closest<HTMLElement>(".bg-gradient-to-br");
  const container = card || resultElement.parentElement;
  if (!container) return;

  if (card) {
    if (card.dataset.resultTone !== interpretation.tone) {
      card.style.background = styles.card;
      card.dataset.resultTone = interpretation.tone;
    }
  }

  let badge = container.nextElementSibling as HTMLElement | null;
  if (!badge || badge.dataset.resultInterpretationBadge !== "true") {
    badge = document.createElement("div");
    badge.dataset.resultInterpretationBadge = "true";
    container.insertAdjacentElement("afterend", badge);
  }

  if (badge.dataset.resultTone !== interpretation.tone || badge.dataset.resultLabel !== interpretation.label) {
    badge.dataset.resultTone = interpretation.tone;
    badge.dataset.resultLabel = interpretation.label;
    badge.className = `mx-auto mt-3 inline-flex items-center gap-2 rounded-full border px-3 py-1.5 text-xs font-bold shadow-sm ${styles.badge}`;
    badge.replaceChildren();

    const dot = document.createElement("span");
    dot.className = `h-2 w-2 rounded-full ${styles.dot}`;
    dot.setAttribute("aria-hidden", "true");

    const label = document.createElement("span");
    label.textContent = interpretation.label;

    badge.append(dot, label);
  }
}

export default function ResultInterpretationEnhancer() {
  useEffect(() => {
    const apply = () => findResultElements().forEach(ensureBadge);
    apply();

    const observer = new MutationObserver(apply);
    observer.observe(document.body, { childList: true, characterData: true, subtree: true });

    return () => observer.disconnect();
  }, []);

  return null;
}
